  1→"use client";
  2→
  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import dynamic from "next/dynamic";
  5→import { chatStream } from "@/lib/api";
  6→import type { CanvasState } from "@/components/OmegaCanvas";
  7→import Landing from "@/components/Landing";
  8→import Sidebar from "@/components/Sidebar/Sidebar";
  9→import ChatHeader from "@/components/ChatHeader/ChatHeader";
 10→import UserMessage from "@/components/MessageBubble/UserMessage";
 11→import OmegaMessage from "@/components/MessageBubble/OmegaMessage";
 12→import ThinkingIndicator from "@/components/MessageBubble/ThinkingIndicator";
 13→import InputArea from "@/components/InputArea/InputArea";
 14→import s from "./page.module.css";
 15→
 16→const OmegaCanvas = dynamic(() => import("@/components/OmegaCanvas"), { ssr: false });
 17→
 18→interface Msg {
 19→  role: "user" | "omega";
 20→  text: string;
 21→  timestamp?: string;
 22→  provider?: string;
 23→}
 24→
 25→export default function Home() {
 26→  const [messages, setMessages] = useState<Msg[]>([]);
 27→  const [animatingIdx, setAnimatingIdx] = useState(-1);
 28→  const [error, setError] = useState<string | null>(null);
 29→  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
 30→  const [statusText, setStatusText] = useState<string | null>(null);
 31→  const [provider, setProvider] = useState<string | null>(null);
 32→  const [sessionId, setSessionId] = useState<string | null>(null);
 33→  const [sidebarOpen, setSidebarOpen] = useState(false);
 34→  const [sessionList, setSessionList] = useState<{ id: string; created_at: string; preview: string }[]>([]);
 35→  const [showPill, setShowPill] = useState(false);
 36→
 37→  const feedRef = useRef<HTMLDivElement>(null);
 38→  const bottomRef = useRef<HTMLDivElement>(null);
 39→  const inChatMode = messages.length > 0;
 40→
 41→  // Load saved session on mount
 42→  useEffect(() => {
 43→    const saved = localStorage.getItem("omega_session");
 44→    if (saved) setSessionId(saved);
 45→  }, []);
 46→
 47→  // Fetch session list for sidebar
 48→  const refreshSessions = useCallback(() => {
 49→    fetch("/api/sessions")
 50→      .then((r) => r.json())
 51→      .then((data) => { if (Array.isArray(data)) setSessionList(data); })
 52→      .catch(console.error);
 53→  }, []);
 54→
 55→  useEffect(() => { refreshSessions(); }, [refreshSessions]);
 56→
 57→  // Scroll management
 58→  const scrollToBottom = () => {
 59→    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
 60→    setShowPill(false);
 61→  };
 62→  const handleScroll = () => {
 63→    const el = feedRef.current;
 64→    if (!el) return;
 65→    setShowPill(el.scrollHeight - el.scrollTop - el.clientHeight > 50);
 66→  };
 67→  useEffect(() => {
 68→    if (!showPill) bottomRef.current?.scrollIntoView({ behavior: "smooth" });
 69→  }, [messages, canvasState, showPill]);
 70→
 71→  // Core send logic (reusable for both landing and chat input)
 72→  const sendMessage = useCallback(
 73→    async (text: string) => {
 74→      if (!text.trim() || canvasState === "thinking") return;
 75→      setError(null);
 76→      const newMsg: Msg = { role: "user", text, timestamp: new Date().toISOString() };
 77→      const currentHistory = [...messages];
 78→      setMessages((prev) => [...prev, newMsg]);
 79→      setCanvasState("thinking");
 80→      setShowPill(false);
 81→
 82→      try {
 83→        const res = await chatStream(
 84→          { user: text, history: currentHistory, sessionId: sessionId ?? undefined },
 85→          (chunk) => {
 86→            setStatusText(null);
 87→            setMessages((prev) => {
 88→              const updated = [...prev];
 89→              const last = updated[updated.length - 1];
 90→              if (last.role === "user") {
 91→                updated.push({ role: "omega", text: chunk, timestamp: new Date().toISOString() });
 92→                setAnimatingIdx(updated.length - 1);
 93→                setCanvasState("idle");
 94→              } else {
 95→                updated[updated.length - 1] = { ...last, text: last.text + chunk };
 96→              }
 97→              return updated;
 98→            });
 99→          },
100→          (status) => setStatusText(status)
101→        );
102→
103→        if (res.sessionId && !sessionId) {
104→          setSessionId(res.sessionId);
105→          localStorage.setItem("omega_session", res.sessionId);
106→        }
107→        if (res.provider) setProvider(res.provider);
108→
109→        // Tag the last omega message with provider
110→        setMessages((prev) => {
111→          const updated = [...prev];
112→          const last = updated[updated.length - 1];
113→          if (last.role === "omega") updated[updated.length - 1] = { ...last, provider: res.provider };
114→          return updated;
115→        });
116→
117→        setAnimatingIdx(-1);
118→        setStatusText(null);
119→        refreshSessions();
120→      } catch (err) {
121→        setError(err instanceof Error ? err.message : String(err));
122→        setCanvasState("idle");
123→        setStatusText(null);
124→      }
125→    },
126→    [canvasState, messages, sessionId, refreshSessions]
127→  );
128→
129→  const loadSession = async (id: string) => {
130→    try {
131→      const res = await fetch(`/api/sessions/${id}`);
132→      const data = await res.json();
133→      if (Array.isArray(data)) {
134→        setMessages(
135→          // eslint-disable-next-line @typescript-eslint/no-explicit-any
136→          data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at }))
137→        );
138→        setSessionId(id);
139→        localStorage.setItem("omega_session", id);
140→        setSidebarOpen(false);
141→      }
142→    } catch (err) {
143→      console.error(err);
144→    }
145→  };
146→
147→  const startNewChat = () => {
148→    setMessages([]);
149→    setAnimatingIdx(-1);
150→    setSessionId(null);
151→    setProvider(null);
152→    localStorage.removeItem("omega_session");
153→    setSidebarOpen(false);
154→  };
155→
156→  // ── Render ──────────────────────────────────────────────────────
157→  return (
158→    <>
159→      <OmegaCanvas state={canvasState} />
160→
161→      <div className={s.appLayout}>
162→        <Sidebar
163→          sessions={sessionList}
164→          activeSessionId={sessionId}
165→          onNewChat={startNewChat}
166→          onSelectSession={loadSession}
167→          isOpen={sidebarOpen}
168→          onToggle={() => setSidebarOpen((o) => !o)}
169→        />
170→
171→        <div className={s.mainArea}>
172→          {!inChatMode ? (
173→            <Landing
174→              onFirstMessage={sendMessage}
175→              isThinking={canvasState === "thinking"}
176→            />
177→          ) : (
178→            <>
179→              <ChatHeader
180→                provider={provider ?? undefined}
181→                thinking={canvasState === "thinking"}
182→                onToggleSidebar={() => setSidebarOpen((o) => !o)}
183→                onNewChat={startNewChat}
184→              />
185→
186→              <div
187→                className={s.feed}
188→                role="log"
189→                aria-live="polite"
190→                aria-label="Chat messages"
191→                ref={feedRef}
192→                onScroll={handleScroll}
193→              >
194→                {messages.map((msg, i) =>
195→                  msg.role === "user" ? (
196→                    <UserMessage key={i} text={msg.text} timestamp={msg.timestamp} />
197→                  ) : (
198→                    <OmegaMessage
199→                      key={i}
200→                      text={msg.text}
201→                      streaming={i === animatingIdx}
202→                      timestamp={msg.timestamp}
203→                      provider={msg.provider}
204→                    />
205→                  )
206→                )}
207→
208→                {canvasState === "thinking" && <ThinkingIndicator status={statusText} />}
209→
210→                {error && (
211→                  <div className={s.error} role="alert">
212→                    ⚠ {error}
213→                  </div>
214→                )}
215→                <div ref={bottomRef} style={{ height: 1 }} />
216→              </div>
217→
218→              {showPill && (
219→                <div className={s.scrollPillWrap}>
220→                  <button className={s.scrollPill} onClick={scrollToBottom} aria-label="Scroll to bottom">
221→                    ↓ New response
222→                  </button>
223→                </div>
224→              )}
225→
226→              <InputArea
227→                onSend={sendMessage}
228→                disabled={canvasState === "thinking"}
229→                autoFocus
230→              />
231→            </>
232→          )}
233→        </div>
234→      </div>
235→    </>
236→  );
237→}
238→

 1→/* ── App Layout — Sidebar + Main ────────────────────────────────── */
 2→.appLayout {
 3→  position: fixed;
 4→  inset: 0;
 5→  display: flex;
 6→  z-index: 1;
 7→}
 8→
 9→.mainArea {
10→  flex: 1;
11→  display: flex;
12→  flex-direction: column;
13→  min-width: 0;
14→  position: relative;
15→  height: 100%;
16→}
17→
18→/* ── Message Feed ──────────────────────────────────────────────── */
19→.feed {
20→  flex: 1;
21→  overflow-y: auto;
22→  overflow-x: hidden;
23→  padding: var(--space-5) var(--space-6);
24→  padding-bottom: 120px;
25→  display: flex;
26→  flex-direction: column;
27→  gap: var(--space-4);
28→  scroll-behavior: smooth;
29→}
30→
31→/* ── Error ──────────────────────────────────────────────────────── */
32→.error {
33→  padding: var(--space-3) var(--space-4);
34→  background: rgba(239, 68, 68, 0.15);
35→  border: 1px solid rgba(239, 68, 68, 0.3);
36→  border-radius: 12px;
37→  color: #fca5a5;
38→  font-size: 0.88rem;
39→  animation: fade-up 0.3s var(--ease-snappy) both;
40→}
41→
42→/* ── Scroll Pill ───────────────────────────────────────────────── */
43→.scrollPillWrap {
44→  position: absolute;
45→  bottom: 100px;
46→  left: 50%;
47→  transform: translateX(-50%);
48→  z-index: 20;
49→  pointer-events: auto;
50→}
51→
52→.scrollPill {
53→  background: var(--glass-bg);
54→  border: 1px solid var(--glass-border);
55→  backdrop-filter: blur(12px);
56→  color: var(--lavender);
57→  padding: var(--space-2) var(--space-4);
58→  border-radius: 20px;
59→  font-size: 0.82rem;
60→  font-family: 'Space Grotesk', sans-serif;
61→  cursor: pointer;
62→  transition: all 0.2s var(--ease-smooth);
63→  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4);
64→}
65→
66→.scrollPill:hover {
67→  background: rgba(99, 102, 241, 0.2);
68→  border-color: var(--indigo);
69→  box-shadow: 0 0 15px rgba(99, 102, 241, 0.3);
70→}
71→
72→/* ── Responsive ────────────────────────────────────────────────── */
73→@media (max-width: 768px) {
74→  .feed {
75→    padding: var(--space-4) var(--space-3);
76→    padding-bottom: 100px;
77→  }
78→}
