 1→"use client";
 2→
 3→import s from "./Sidebar.module.css";
 4→import SessionItem from "./SessionItem";
 5→
 6→export interface SessionEntry {
 7→  id: string;
 8→  preview: string;
 9→  created_at: string;
10→}
11→
12→interface SidebarProps {
13→  sessions: SessionEntry[];
14→  activeSessionId: string | null;
15→  onNewChat: () => void;
16→  onSelectSession: (id: string) => void;
17→  isOpen: boolean;
18→  onToggle: () => void;
19→}
20→
21→export default function Sidebar({
22→  sessions,
23→  activeSessionId,
24→  onNewChat,
25→  onSelectSession,
26→  isOpen,
27→  onToggle,
28→}: SidebarProps) {
29→  return (
30→    <>
31→      {/* Mobile hamburger */}
32→      {!isOpen && (
33→        <button className={s.hamburger} onClick={onToggle} aria-label="Open sidebar">
34→          &#9776;
35→        </button>
36→      )}
37→
38→      {/* Mobile overlay */}
39→      {isOpen && <div className={s.overlay} onClick={onToggle} />}
40→
41→      {/* Sidebar panel */}
42→      <aside className={`${s.sidebar} ${isOpen ? s.sidebarOpen : ""}`}>
43→        <div className={s.brand}>
44→          <span className={s.omega}>&Omega;</span>
45→          <span className={s.brandName}>OmegA</span>
46→          <button className={s.toggle} onClick={onToggle} aria-label="Close sidebar">
47→            &times;
48→          </button>
49→        </div>
50→
51→        <button className={s.newChat} onClick={onNewChat}>
52→          <span className={s.newChatIcon}>+</span>
53→          New Chat
54→        </button>
55→
56→        <div className={s.divider} />
57→        <div className={s.sectionLabel}>Recent Sessions</div>
58→
59→        <div className={s.sessionList}>
60→          {sessions.length === 0 ? (
61→            <div className={s.empty}>No sessions yet.<br />Start a conversation.</div>
62→          ) : (
63→            sessions.map((session) => (
64→              <SessionItem
65→                key={session.id}
66→                id={session.id}
67→                preview={session.preview}
68→                created_at={session.created_at}
69→                isActive={session.id === activeSessionId}
70→                onSelect={onSelectSession}
71→              />
72→            ))
73→          )}
74→        </div>
75→      </aside>
76→    </>
77→  );
78→}
79→

