  1→"use client";
  2→
  3→import { useState, useRef, useCallback } from "react";
  4→import s from "./Landing.module.css";
  5→
  6→interface LandingProps {
  7→  onFirstMessage: (text: string) => void;
  8→  isThinking?: boolean;
  9→}
 10→
 11→const FEATURES = [
 12→  {
 13→    icon: "\u039C",
 14→    title: "Persistent Memory",
 15→    desc: "MYELIN graph memory hardens retrieval paths with use — nothing is forgotten.",
 16→  },
 17→  {
 18→    icon: "\u03A6",
 19→    title: "Identity Anchoring",
 20→    desc: "AEON Phylactery chain ensures cryptographic continuity of self across sessions.",
 21→  },
 22→  {
 23→    icon: "\u03A3",
 24→    title: "Synthesis Engine",
 25→    desc: "ADCCL cognitive control loop with claim budgets and anti-drift self-tagging.",
 26→  },
 27→  {
 28→    icon: "\u0391",
 29→    title: "Governed Reasoning",
 30→    desc: "AEGIS policy shell enforces model-agnostic governance at the API boundary.",
 31→  },
 32→];
 33→
 34→export default function Landing({ onFirstMessage, isThinking = false }: LandingProps) {
 35→  const [input, setInput] = useState("");
 36→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 37→
 38→  const autoResize = () => {
 39→    if (!textareaRef.current) return;
 40→    textareaRef.current.style.height = "auto";
 41→    textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 180)}px`;
 42→  };
 43→
 44→  const handleSubmit = useCallback(
 45→    (e?: React.FormEvent) => {
 46→      e?.preventDefault();
 47→      const text = input.trim();
 48→      if (!text || isThinking) return;
 49→      setInput("");
 50→      onFirstMessage(text);
 51→    },
 52→    [input, isThinking, onFirstMessage],
 53→  );
 54→
 55→  const handleKey = (e: React.KeyboardEvent) => {
 56→    if (e.key === "Enter" && !e.shiftKey) {
 57→      e.preventDefault();
 58→      handleSubmit();
 59→    }
 60→  };
 61→
 62→  return (
 63→    <div className={s.landing}>
 64→      <div className={s.vignette} />
 65→
 66→      {/* Hero */}
