 3→import { useState, useRef, useEffect, useCallback } from 'react';
 4→import s from './InputArea.module.css';
 5→
 6→interface InputAreaProps {
 7→  onSend: (text: string) => void;
 8→  disabled: boolean;
 9→  autoFocus: boolean;
10→}
11→
12→export default function InputArea({ onSend, disabled, autoFocus }: InputAreaProps) {
13→  const [value, setValue] = useState('');
14→  const ref = useRef<HTMLTextAreaElement>(null);
15→
16→  const resize = useCallback(() => {
17→    const el = ref.current;
18→    if (!el) return;
19→    el.style.height = 'auto';
20→    const lineH = parseFloat(getComputedStyle(el).lineHeight) || 22;
21→    const maxH = lineH * 6;
22→    el.style.height = `${Math.min(el.scrollHeight, maxH)}px`;
23→  }, []);
24→
25→  useEffect(() => {
26→    if (autoFocus && !disabled) ref.current?.focus();
27→  }, [autoFocus, disabled]);
28→
29→  const send = () => {
30→    const text = value.trim();
31→    if (!text || disabled) return;
32→    onSend(text);
33→    setValue('');
34→    // Reset height after clearing
35→    requestAnimationFrame(() => {
36→      if (ref.current) {
37→        ref.current.style.height = 'auto';
38→      }
39→    });
40→  };
41→
42→  const handleKey = (e: React.KeyboardEvent) => {
43→    if (e.key === 'Enter' && !e.shiftKey) {
44→      e.preventDefault();
45→      send();
46→    }
47→  };
48→
49→  return (
50→    <div className={s.wrap}>
51→      <div className={`${s.bar} ${value.trim() ? s.hasInput : ''} ${disabled ? s.disabled : ''}`}>
52→        <textarea
53→          ref={ref}
54→          className={s.textarea}
55→          value={value}
56→          onChange={e => { setValue(e.target.value); resize(); }}
57→          onKeyDown={handleKey}
58→          placeholder="Ask OmegA anything..."
59→          rows={1}
60→          disabled={disabled}
61→          autoFocus={autoFocus}
62→        />
63→        <div className={s.meta}>
64→          {value.length > 0 && <span className={s.charCount}>{value.length}</span>}
65→        </div>
66→        <button
67→          className={`${s.sendBtn} ${value.trim() ? s.glow : ''}`}
68→          onClick={send}
69→          disabled={!value.trim() || disabled}
70→          aria-label="Send message"
71→          type="button"
72→        >
73→          Ω
74→        </button>
75→      </div>
76→    </div>
77→  );
78→}
79→

