  8→/* ── Code block with copy button and dark inline theme ──────────── */
  9→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 10→function CodeBlock({ inline, className, children, ...props }: any) {
 11→  const lang = /language-(\w+)/.exec(className || '')?.[1];
 12→  const [copied, setCopied] = useState(false);
 13→
 14→  const copy = () => {
 15→    navigator.clipboard.writeText(String(children).replace(/\n$/, ''));
 16→    setCopied(true);
 17→    setTimeout(() => setCopied(false), 2000);
 18→  };
 19→
 20→  if (!inline && lang) {
 21→    return (
 22→      <div className={s.codeWrap}>
 23→        <div className={s.codeHeader}>
 24→          <span className={s.codeLang}>{lang}</span>
 25→          <button className={s.codeCopy} onClick={copy} aria-label="Copy code">
 26→            {copied ? '✓ Copied' : 'Copy'}
 27→          </button>
 28→        </div>
 29→        <pre
 30→          style={{
 31→            margin: 0,
 32→            padding: '1rem',
 33→            background: 'rgba(2, 2, 12, 0.92)',
 34→            borderRadius: '0 0 0.75rem 0.75rem',
 35→            overflowX: 'auto',
 36→            fontSize: '0.85rem',
 37→            lineHeight: 1.6,
 38→            color: '#c4b5fd',
 39→          }}
 40→        >
 41→          <code className={className} {...props} style={{ color: '#c4b5fd' }}>
 42→            {children}
 43→          </code>
 44→        </pre>
 45→      </div>
 46→    );
 47→  }
 48→
 49→  return (
 50→    <code
 51→      className={className}
 52→      {...props}
 53→      style={{
 54→        background: 'rgba(99, 102, 241, 0.12)',
 55→        padding: '0.15em 0.4em',
 56→        borderRadius: '0.3em',
 57→        fontSize: '0.88em',
 58→        color: '#c4b5fd',
 59→      }}
 60→    >
 61→      {children}
 62→    </code>
 63→  );
 64→}
