"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import dynamic from "next/dynamic";
import { chatStream } from "@/lib/api";
import type { CanvasState } from "@/components/OmegaCanvas";
import Sidebar from "@/components/Sidebar/Sidebar";
import ChatHeader from "@/components/ChatHeader/ChatHeader";
import UserMessage from "@/components/MessageBubble/UserMessage";
import OmegaMessage from "@/components/MessageBubble/OmegaMessage";
import ThinkingIndicator from "@/components/MessageBubble/ThinkingIndicator";
import InputArea from "@/components/InputArea/InputArea";
import s from "./page.module.css";

const OmegaCanvas = dynamic(() => import("@/components/OmegaCanvas"), { ssr: false });

interface Msg {
  role: "user" | "omega";
  text: string;
  timestamp?: string;
  provider?: string;
}

export default function Home() {
  const [messages, setMessages] = useState<Msg[]>([]);
  const [animatingIdx, setAnimatingIdx] = useState(-1);
  const [error, setError] = useState<string | null>(null);
  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
  const [statusText, setStatusText] = useState<string | null>(null);
  const [provider, setProvider] = useState<string | null>(null);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sessionList, setSessionList] = useState<{ id: string; created_at: string; preview: string }[]>([]);
  const [showPill, setShowPill] = useState(false);

  const feedRef = useRef<HTMLDivElement>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  // Load saved session on mount
  useEffect(() => {
    const saved = localStorage.getItem("omega_session");
    if (saved) setSessionId(saved);
  }, []);

  // Fetch session list for sidebar
  const refreshSessions = useCallback(() => {
    fetch("/api/sessions")
      .then((r) => r.json())
      .then((data) => { if (Array.isArray(data)) setSessionList(data); })
      .catch(console.error);
  }, []);

  useEffect(() => { refreshSessions(); }, [refreshSessions]);

  // Scroll management
  const scrollToBottom = () => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
    setShowPill(false);
  };
  const handleScroll = () => {
    const el = feedRef.current;
    if (!el) return;
    setShowPill(el.scrollHeight - el.scrollTop - el.clientHeight > 50);
  };
  useEffect(() => {
    if (!showPill) bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, canvasState, showPill]);

  // Core send logic
  const sendMessage = useCallback(
    async (text: string) => {
      if (!text.trim() || canvasState === "thinking") return;
      setError(null);
      const newMsg: Msg = { role: "user", text, timestamp: new Date().toISOString() };
      const currentHistory = [...messages];
      setMessages((prev) => [...prev, newMsg]);
      setCanvasState("thinking");
      setShowPill(false);

      try {
        const res = await chatStream(
          { user: text, history: currentHistory, sessionId: sessionId ?? undefined },
          (chunk) => {
            setStatusText(null);
            setMessages((prev) => {
              const updated = [...prev];
              const last = updated[updated.length - 1];
              if (last.role === "user") {
                updated.push({ role: "omega", text: chunk, timestamp: new Date().toISOString() });
                setAnimatingIdx(updated.length - 1);
                setCanvasState("idle");
              } else {
                updated[updated.length - 1] = { ...last, text: last.text + chunk };
              }
              return updated;
            });
          },
          (status) => setStatusText(status)
        );

        if (res.sessionId && !sessionId) {
          setSessionId(res.sessionId);
          localStorage.setItem("omega_session", res.sessionId);
        }
        if (res.provider) setProvider(res.provider);

        // Tag the last omega message with provider
        setMessages((prev) => {
          const updated = [...prev];
          const last = updated[updated.length - 1];
          if (last.role === "omega") updated[updated.length - 1] = { ...last, provider: res.provider };
          return updated;
        });

        setAnimatingIdx(-1);
        setStatusText(null);
        refreshSessions();
      } catch (err) {
        setError(err instanceof Error ? err.message : String(err));
        setCanvasState("idle");
        setStatusText(null);
      }
    },
    [canvasState, messages, sessionId, refreshSessions]
  );

  const loadSession = async (id: string) => {
    try {
      const res = await fetch(`/api/sessions/${id}`);
      const data = await res.json();
      if (Array.isArray(data)) {
        setMessages(
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at }))
        );
        setSessionId(id);
        localStorage.setItem("omega_session", id);
        setSidebarOpen(false);
      }
    } catch (err) {
      console.error(err);
    }
  };

  const startNewChat = () => {
    setMessages([]);
    setAnimatingIdx(-1);
    setSessionId(null);
    setProvider(null);
    localStorage.removeItem("omega_session");
    setSidebarOpen(false);
  };

  // Close sidebar when clicking outside on mobile
  const handleMainClick = () => {
    if (sidebarOpen && window.innerWidth < 768) {
      setSidebarOpen(false);
    }
  };

  const hasMessages = messages.length > 0;

  // ── Render ──────────────────────────────────────────────────────
  return (
    <>
      <OmegaCanvas state={canvasState} />

      <div className={s.appLayout}>
        <Sidebar
          sessions={sessionList}
          activeSessionId={sessionId}
          onNewChat={startNewChat}
          onSelectSession={loadSession}
          isOpen={sidebarOpen}
          onToggle={() => setSidebarOpen((o) => !o)}
        />

        <div className={s.mainArea} onClick={handleMainClick}>
          <ChatHeader
            provider={provider ?? undefined}
            thinking={canvasState === "thinking"}
            onToggleSidebar={() => setSidebarOpen((o) => !o)}
            onNewChat={startNewChat}
          />

          <div
            className={s.feed}
            role="log"
            aria-live="polite"
            aria-label="Chat messages"
            ref={feedRef}
            onScroll={handleScroll}
          >
            {!hasMessages && (
              <div className={s.emptyState}>
                <div className={s.emptyOmega}>{"\u03A9"}</div>
                <div className={s.emptyLabel}>Ask OmegA anything</div>
              </div>
            )}

            {messages.map((msg, i) =>
              msg.role === "user" ? (
                <UserMessage key={i} text={msg.text} timestamp={msg.timestamp} />
              ) : (
                <OmegaMessage
                  key={i}
                  text={msg.text}
                  streaming={i === animatingIdx}
                  timestamp={msg.timestamp}
                  provider={msg.provider}
                />
              )
            )}

            {canvasState === "thinking" && <ThinkingIndicator status={statusText} />}

            {error && (
              <div className={s.error} role="alert">
                {error}
              </div>
            )}
            <div ref={bottomRef} style={{ height: 1 }} />
          </div>

          {showPill && (
            <div className={s.scrollPillWrap}>
              <button className={s.scrollPill} onClick={scrollToBottom} aria-label="Scroll to bottom">
                New response
              </button>
            </div>
          )}

          <InputArea
            onSend={sendMessage}
            disabled={canvasState === "thinking"}
            autoFocus
          />
        </div>
      </div>
    </>
  );
}

/* ── App Layout — Sidebar + Main ────────────────────────────────── */
.appLayout {
  position: fixed;
  inset: 0;
  display: flex;
  z-index: 1;
}

.mainArea {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  position: relative;
  height: 100%;
}

/* ── Message Feed ──────────────────────────────────────────────── */
.feed {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: var(--space-5) var(--space-6);
  padding-bottom: 1rem;
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  scroll-behavior: smooth;
}

/* ── Empty State (shown when no messages) ─────────────────────── */
.emptyState {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);
  user-select: none;
  pointer-events: none;
}

.emptyOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(80px, 18vw, 140px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  animation: omega-breathe 4s ease-in-out infinite;
  will-change: filter;
}

.emptyLabel {
  font-family: 'Space Grotesk', sans-serif;
  font-size: clamp(14px, 2.5vw, 17px);
  color: var(--dim);
  letter-spacing: 0.12em;
}

/* ── Error ──────────────────────────────────────────────────────── */
.error {
  padding: var(--space-3) var(--space-4);
  background: rgba(239, 68, 68, 0.15);
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: 12px;
  color: #fca5a5;
  font-size: 0.88rem;
  animation: fade-up 0.3s var(--ease-snappy) both;
}

/* ── Scroll Pill ───────────────────────────────────────────────── */
.scrollPillWrap {
  position: absolute;
  bottom: 100px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 20;
  pointer-events: auto;
}

.scrollPill {
  background: var(--glass-bg);
  border: 1px solid var(--glass-border);
  backdrop-filter: blur(12px);
  color: var(--lavender);
  padding: var(--space-2) var(--space-4);
  border-radius: 20px;
  font-size: 0.82rem;
  font-family: 'Space Grotesk', sans-serif;
  cursor: pointer;
  transition: all 0.2s var(--ease-smooth);
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4);
}

.scrollPill:hover {
  background: rgba(99, 102, 241, 0.2);
  border-color: var(--indigo);
  box-shadow: 0 0 15px rgba(99, 102, 241, 0.3);
}

/* ── Responsive ────────────────────────────────────────────────── */
@media (max-width: 768px) {
  .feed {
    padding: var(--space-4) var(--space-3);
    padding-bottom: 0.75rem;
  }
}

"use client";

import s from "./Sidebar.module.css";
import SessionItem from "./SessionItem";

export interface SessionEntry {
  id: string;
  preview: string;
  created_at: string;
}

interface SidebarProps {
  sessions: SessionEntry[];
  activeSessionId: string | null;
  onNewChat: () => void;
  onSelectSession: (id: string) => void;
  isOpen: boolean;
  onToggle: () => void;
}

export default function Sidebar({
  sessions,
  activeSessionId,
  onNewChat,
  onSelectSession,
  isOpen,
  onToggle,
}: SidebarProps) {
  return (
    <>
      {/* Mobile overlay */}
      {isOpen && <div className={s.overlay} onClick={onToggle} />}

      {/* Sidebar panel */}
      <aside className={`${s.sidebar} ${isOpen ? s.sidebarOpen : ""}`}>
        <div className={s.brand}>
          <span className={s.omega}>&Omega;</span>
          <span className={s.brandName}>OmegA</span>
          <button className={s.toggle} onClick={onToggle} aria-label="Close sidebar">
            &times;
          </button>
        </div>

        <button className={s.newChat} onClick={onNewChat}>
          <span className={s.newChatIcon}>+</span>
          New Chat
        </button>

        <div className={s.divider} />
        <div className={s.sectionLabel}>Recent Sessions</div>

        <div className={s.sessionList}>
          {sessions.length === 0 ? (
            <div className={s.empty}>No sessions yet.<br />Start a conversation.</div>
          ) : (
            sessions.map((session) => (
              <SessionItem
                key={session.id}
                id={session.id}
                preview={session.preview}
                created_at={session.created_at}
                isActive={session.id === activeSessionId}
                onSelect={onSelectSession}
              />
            ))
          )}
        </div>

        <div className={s.divider} />
        <div className={s.aboutSection}>
          <div className={s.sectionLabel}>About OmegA</div>
          <a href="/about" className={s.aboutLink}>Architecture Overview</a>
          <a href="https://github.com/Mega-Therion/OmegA-Architecture" target="_blank" rel="noopener noreferrer" className={s.aboutLink}>GitHub Repository</a>
        </div>
      </aside>
    </>
  );
}

/* ── Overlay (mobile) ─────────────────────────────────────── */
.overlay {
  display: none;
}

@media (max-width: 767px) {
  .overlay {
    display: block;
    position: fixed;
    inset: 0;
    background: rgba(2, 2, 12, 0.6);
    backdrop-filter: blur(4px);
    z-index: 998;
    animation: fadeIn 0.2s ease;
  }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

/* ── Sidebar ─────────────────────────────────────────────── */
.sidebar {
  position: relative;
  top: 0;
  left: 0;
  bottom: 0;
  width: 280px;
  flex-shrink: 0;
  z-index: 999;
  display: flex;
  flex-direction: column;
  background: var(--glass-bg);
  border-right: 1px solid var(--glass-border);
  backdrop-filter: blur(24px) saturate(1.4);
  -webkit-backdrop-filter: blur(24px) saturate(1.4);
  transition: width 0.3s cubic-bezier(0.4, 0, 0.2, 1), transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

/* Desktop: collapsed = zero width */
@media (min-width: 768px) {
  .sidebar {
    width: 0;
    min-width: 0;
  }
  .sidebarOpen {
    width: 280px;
  }
}

/* Mobile: slide from left */
@media (max-width: 767px) {
  .sidebar {
    position: fixed;
    width: 280px;
    transform: translateX(-100%);
  }

  .sidebarOpen {
    transform: translateX(0);
  }
}

